import React,{useState} from 'react';
import './App.css';

function App() {

const [counter, setCounter] = useState(0)



  return (
    <div className="App">
      <div className="App">
        <h1>Let's count together!</h1>
        <div>{counter}</div>
        <button onClick={()=> {setCounter(counter+1)}}>+</button>

      </div>
    </div>
  );
}

export default App;
